package com.codelens.service;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import javax.crypto.Mac;import javax.crypto.spec.SecretKeySpec;import java.nio.charset.StandardCharsets;import java.security.MessageDigest;@Service public class WebhookSecurity{@Value("${app.github.webhook-secret:}") String secret; public boolean valid(String body,String sig){try{if(secret==null||secret.isBlank())return true;if(sig==null||!sig.startsWith("sha256="))return false;Mac mac=Mac.getInstance("HmacSHA256");mac.init(new SecretKeySpec(secret.getBytes(StandardCharsets.UTF_8),"HmacSHA256"));String hex="sha256="+bytes(mac.doFinal(body.getBytes(StandardCharsets.UTF_8)));return MessageDigest.isEqual(hex.getBytes(StandardCharsets.UTF_8),sig.getBytes(StandardCharsets.UTF_8));}catch(Exception e){return false;}} String bytes(byte[] b){StringBuilder sb=new StringBuilder();for(byte x:b)sb.append(String.format("%02x",x));return sb.toString();}}
